/**
 * Node 1: Split Markdown into Chunks
 * Prepares markdown for parallel LLM processing
 */

const MAX_CHUNK_SIZE = 3000; // Adjust based on your LLM's context window
const OVERLAP_SIZE = 200;    // Overlap for context continuity

/**
 * Split markdown intelligently by paragraphs and sections
 */
function splitMarkdown(markdown, maxSize, overlap) {
  const chunks = [];
  const paragraphs = markdown.split(/\n\n+/);

  let currentChunk = '';
  let chunkIndex = 0;
  let previousOverlap = '';

  for (const paragraph of paragraphs) {
    const testChunk = currentChunk + (currentChunk ? '\n\n' : '') + paragraph;

    // If adding this paragraph exceeds limit, save current chunk
    if (testChunk.length > maxSize && currentChunk.length > 0) {
      chunks.push({
        index: chunkIndex,
        content: currentChunk. trim(),
        size: currentChunk.length,
        hasOverlap: chunkIndex > 0
      });

      // Get overlap from end of current chunk
      previousOverlap = currentChunk. slice(-overlap);
      chunkIndex++;

      // Start new chunk with overlap
      currentChunk = previousOverlap + '\n\n' + paragraph;
    } else {
      currentChunk = testChunk;
    }
  }

  // Add final chunk
  if (currentChunk. trim(). length > 0) {
    chunks.push({
      index: chunkIndex,
      content: currentChunk.trim(),
      size: currentChunk.length,
      hasOverlap: chunkIndex > 0
    });
  }

  return chunks;
}

// Get input markdown
const inputMarkdown = $input.first(). json.markdown || 
                      $input.first().json. content || 
                      $input.first().json.text;

if (!inputMarkdown) {
  throw new Error('No markdown content found.  Expected field: markdown, content, or text');
}

// Split into chunks
const chunks = splitMarkdown(inputMarkdown, MAX_CHUNK_SIZE, OVERLAP_SIZE);

// Return each chunk as a separate item for parallel processing
return chunks.map(chunk => ({
  json: {
    chunkContent: chunk.content,
    chunkIndex: chunk.index,
    totalChunks: chunks.length,
    chunkSize: chunk.size,
    chunkContext: `[Processing chunk ${chunk.index + 1} of ${chunks.length}]`,
    originalDocumentLength: inputMarkdown.length
  }
}));

