/**
 * Node 4: Parse and Merge LLM Outputs
 * Consolidates all parallel LLM responses into single result
 */

const allItems = $input.all();

// Initialize merged result
const mergedResult = {
  output: [],
  metadata: {
    generatedAt: new Date().toISOString(),
    proofreader: null,
    model: null,
    version: null,
    totalErrors: 0,
    totalChunks: allItems.length,
    chunksProcessed: 0,
    parseErrors: []
  }
};

// Track unique metadata values
const metadataValues = {
  proofreader: new Set(),
  model: new Set(),
  version: new Set()
};

// Process each chunk
allItems.forEach((item, index) => {
  try {
    // Get the LLM output (might be in different fields depending on LLM node)
    const outputString = item.json.output || 
                        item.json.response || 
                        item.json.message || 
                        item.json.text;

    // Parse if it's a string, otherwise use as-is
    const parsedData = typeof outputString === 'string' 
      ? JSON.parse(outputString) 
      : outputString;

    // Extract output array
    const outputArray = parsedData.output || [];

    // Merge outputs with chunk tracking
    if (Array.isArray(outputArray)) {
      outputArray.forEach(section => {
        mergedResult.output.push({
          ... section,
          sourceChunk: index,
          chunkIndex: item.json.chunkIndex
        });
      });
    }

    // Aggregate metadata
    if (parsedData.metadata) {
      const meta = parsedData.metadata;

      if (meta.totalErrors) {
        mergedResult.metadata.totalErrors += meta.totalErrors;
      }

      if (meta.proofreader) metadataValues.proofreader.add(meta.proofreader);
      if (meta.model) metadataValues. model.add(meta.model);
      if (meta.version) metadataValues.version. add(meta.version);
    }

    mergedResult.metadata.chunksProcessed++;

  } catch (error) {
    mergedResult.metadata.parseErrors.push({
      chunkIndex: index,
      error: error.message,
      rawPreview: (item.json.output || '').substring(0, 200)
    });
    console.error(`Parse error in chunk ${index}:`, error.message);
  }
});

// Set consolidated metadata
mergedResult.metadata.proofreader = Array.from(metadataValues.proofreader).join(', ') || 'CBT Editor';
mergedResult.metadata.model = Array.from(metadataValues.model). join(', ') || 'Unknown';
mergedResult.metadata.version = Array.from(metadataValues.version).join(', ') || '1.0';

// Sort by page number, then chunk index
mergedResult.output.sort((a, b) => {
  const pageCompare = (parseInt(a.page) || 0) - (parseInt(b.page) || 0);
  if (pageCompare !== 0) return pageCompare;
  return (a.chunkIndex || 0) - (b.chunkIndex || 0);
});

// Calculate statistics
mergedResult.metadata.statistics = {
  totalPages: new Set(mergedResult.output. map(o => o.page)).size,
  totalUnits: new Set(mergedResult.output.map(o => o.unit)).size,
  totalSections: mergedResult.output.length,
  errorsBySeverity: {},
  errorsByType: {},
  errorsByElement: {}
};

// Aggregate error statistics
mergedResult.output.forEach(section => {
  if (section.errors && Array.isArray(section.errors)) {
    section.errors. forEach(error => {
      // By severity
      const severity = error.severity || 'unknown';
      mergedResult.metadata.statistics.errorsBySeverity[severity] = 
        (mergedResult.metadata.statistics.errorsBySeverity[severity] || 0) + 1;

      // By type
      const errorType = error.errorType || 'unknown';
      mergedResult.metadata.statistics.errorsByType[errorType] = 
        (mergedResult.metadata.statistics.errorsByType[errorType] || 0) + 1;

      // By element
      const elementType = error.elementType || 'unknown';
      mergedResult.metadata.statistics.errorsByElement[elementType] = 
        (mergedResult.metadata.statistics.errorsByElement[elementType] || 0) + 1;
    });
  }
});

// Clean up if no parse errors
if (mergedResult.metadata.parseErrors.length === 0) {
  delete mergedResult.metadata.parseErrors;
}

// Return single merged item
return [{ json: mergedResult }];
